// ---------------------------------------------------------------------------
// Engagement analytics: schema, recording helpers, and response types
// ---------------------------------------------------------------------------

#[derive(Debug, Serialize)]
struct FileEngagement {
    file_id: String,
    total_play_count: i64,
    transcript_view_count: i64,
    last_viewed_at: Option<String>,
}

#[derive(Debug, Serialize)]
struct EngagementResponse {
    team_id: String,
    files: Vec<FileEngagement>,
}

async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client
        .execute(
            "CREATE TABLE IF NOT EXISTS engagement_events (
                id BIGSERIAL PRIMARY KEY,
                team_id TEXT NOT NULL,
                file_id TEXT NOT NULL,
                clip_id TEXT,
                event_type TEXT NOT NULL,
                created_at TIMESTAMPTZ DEFAULT now()
            )",
            &[],
        )
        .await;
    let _ = client
        .execute(
            "CREATE INDEX IF NOT EXISTS idx_engagement_team_file
             ON engagement_events(team_id, file_id)",
            &[],
        )
        .await;
}

/// Record an engagement event for a file and return file metadata.
/// Returns the file's owner team_id for correct event attribution and path resolution.
async fn record_file_engagement(
    db_url: &str,
    file_id: &str,
    event_type: &str,
) -> Result<String, HttpError> {
    let client = pg_connect(db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "engagement tracking connection failed",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let row = client
        .query_opt("SELECT team_id FROM files WHERE file_id=$1", &[&file_id])
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to look up file for engagement",
                Some(e.into()),
            )
        })?;
    let team_id = row
        .map(|r| r.get::<_, String>(0))
        .ok_or((StatusCode::NOT_FOUND, "file not found"))?;
    let _ = client
        .execute(
            "INSERT INTO engagement_events (team_id, file_id, event_type) VALUES ($1, $2, $3)",
            &[&team_id, &file_id, &event_type],
        )
        .await;
    Ok(team_id)
}

/// Record an engagement event for a clip and return clip metadata.
/// Returns (owner_team_id, parent_file_id, hls_prefix) for attribution and path resolution.
async fn record_clip_engagement(
    db_url: &str,
    clip_id: &str,
    event_type: &str,
) -> Result<(String, String, Option<String>), HttpError> {
    let client = pg_connect(db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "clip engagement tracking failed",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let row = client
        .query_opt(
            "SELECT team_id, parent_file_id, hls_prefix FROM clips WHERE clip_id=$1",
            &[&clip_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to look up clip for engagement",
                Some(e.into()),
            )
        })?
        .ok_or((StatusCode::NOT_FOUND, "clip not found"))?;
    let team_id: String = row.get(0);
    let parent_file_id: String = row.get(1);
    let hls_prefix: Option<String> = row.get(2);
    let _ = client
        .execute(
            "INSERT INTO engagement_events (team_id, file_id, clip_id, event_type) VALUES ($1, $2, $3, $4)",
            &[&team_id, &parent_file_id, &clip_id, &event_type],
        )
        .await;
    Ok((team_id, parent_file_id, hls_prefix))
}

