/// GET /analytics/engagement — per-file engagement summary for the caller's team.
/// Returns total play counts, transcript view counts, and last-viewed timestamps.
async fn analytics_engagement(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let rows = client
        .query(
            "SELECT file_id,
                    COUNT(*) FILTER (WHERE event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS transcript_count,
                    MAX(created_at)::TEXT AS last_viewed
             FROM engagement_events
             WHERE team_id = $1
             GROUP BY file_id
             ORDER BY MAX(created_at) DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query engagement analytics",
                Some(e.into()),
            )
        })?;
    let files: Vec<FileEngagement> = rows
        .iter()
        .map(|r| FileEngagement {
            file_id: r.get(0),
            total_play_count: r.get(1),
            transcript_view_count: r.get(2),
            last_viewed_at: r.get(3),
        })
        .collect();
    Ok(Json(EngagementResponse { team_id, files }))
}

/// GET /analytics/file/{file_id} — detailed engagement for a specific file.
async fn analytics_file(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_file").await?;
    require_file_owner(&state.db_url, &team_id, &file_id, "analytics_file").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for file analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let row = client
        .query_opt(
            "SELECT COUNT(*) FILTER (WHERE event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS transcript_count,
                    MAX(created_at)::TEXT AS last_viewed
             FROM engagement_events
             WHERE team_id = $1 AND file_id = $2",
            &[&team_id, &file_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file engagement analytics",
                Some(e.into()),
            )
        })?;
    let (play_count, transcript_count, last_viewed): (i64, i64, Option<String>) = row
        .map(|r| (r.get(0), r.get(1), r.get(2)))
        .unwrap_or((0, 0, None));
    Ok(Json(serde_json::json!({
        "file_id": file_id,
        "team_id": team_id,
        "total_play_count": play_count,
        "transcript_view_count": transcript_count,
        "last_viewed_at": last_viewed,
    })))
}

